import { useEffect, useRef } from 'react';
import { loadStats, formatMs, DIFFICULTIES_IN_ORDER } from './stats-store.js';
import { useStreakStore } from '../../state/streak-store.js';
import './stats.css';

/* ─────────────────────────────────────────────────────────────────────────
 * StatsSheet — personal lifetime stats, lazy-loaded from settings.
 *
 * Shows:
 *   - Headline streak + longest + freezes
 *   - Total puzzles won (sum across difficulties)
 *   - Total perfect wins (0 mistakes / 0 hints)
 *   - Per-difficulty card: count, best time, avg mistakes, perfect wins
 *
 * Pure presentation — no mutation. Reads stats + streak straight off
 * persistence on mount; no live subscription needed since the sheet
 * unmounts immediately after the player closes it.
 * ───────────────────────────────────────────────────────────────────────── */

interface Props { onClose: () => void }

export function StatsSheet({ onClose }: Props) {
  const stats = loadStats();
  const streak = useStreakStore((s) => s.state);
  const sheetRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if (e.key === 'Escape') { e.preventDefault(); onClose(); }
    }
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [onClose]);

  // Aggregate totals across all difficulties — O(6).
  let totalWins = 0;
  let totalPerfect = 0;
  let totalMistakes = 0;
  for (const d of DIFFICULTIES_IN_ORDER) {
    const c = stats.byDifficulty[d];
    totalWins += c.puzzlesWon;
    totalPerfect += c.perfectWins;
    totalMistakes += c.totalMistakes;
  }

  return (
    <div
      className="stats-backdrop"
      role="dialog"
      aria-modal="true"
      aria-label="Personal statistics"
      onClick={onClose}
    >
      <div ref={sheetRef} className="stats-sheet" onClick={(e) => e.stopPropagation()}>
        <button className="sheet-close" aria-label="Close stats" onClick={onClose}>×</button>
        <h2>Your stats</h2>

        <div className="stats-headline">
          <StatBlock label="Current streak" value={streak.current} suffix="day" />
          <StatBlock label="Longest" value={streak.longest} suffix="day" />
          <StatBlock label="Freezes" value={streak.freezes} icon="❄" />
        </div>

        <div className="stats-headline">
          <StatBlock label="Puzzles won" value={totalWins} />
          <StatBlock label="Perfect" value={totalPerfect} />
          <StatBlock label="Total mistakes" value={totalMistakes} />
        </div>

        <h3>By difficulty</h3>
        <div className="diff-list">
          {DIFFICULTIES_IN_ORDER.map((d) => {
            const c = stats.byDifficulty[d];
            const avg = c.puzzlesWon === 0 ? '—' : (c.totalMistakes / c.puzzlesWon).toFixed(1);
            return (
              <div key={d} className="diff-row">
                <div className="diff-name">{d}</div>
                <div className="diff-stats">
                  <span><strong>{c.puzzlesWon}</strong> won</span>
                  <span>Best <strong>{formatMs(c.bestTimeMs)}</strong></span>
                  <span>Avg <strong>{avg}</strong> errs</span>
                  {c.perfectWins > 0 && <span className="perfect">★ {c.perfectWins} perfect</span>}
                </div>
              </div>
            );
          })}
        </div>
        {totalWins === 0 && (
          <p className="empty-note">No wins yet — finish a puzzle and check back!</p>
        )}
      </div>
    </div>
  );
}

function StatBlock({ label, value, suffix, icon }: { label: string; value: number; suffix?: string; icon?: string }) {
  return (
    <div className="stat-block">
      <div className="stat-value">
        {icon && <span className="stat-icon">{icon}</span>}
        {value}
        {suffix && <span className="stat-suffix"> {value === 1 ? suffix : suffix + 's'}</span>}
      </div>
      <div className="stat-label">{label}</div>
    </div>
  );
}
